/**
 * Forgot Password Page
 * 
 * Allows users to initiate password reset by entering their email address.
 * Validates email format and navigates to the password reset flow.
 */

import React, { useState, useEffect, useId } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services';
import { createForgotPasswordSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { LanguageSelector } from '@/shared/components';
import logger from '@/shared/utils/logger.js';
import '/styles/index.css';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

const ForgotPassword = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  // Generate unique ID for email input for accessibility
  const emailId = useId();

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;


  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [emailSent, setEmailSent] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();

    setError('');

    const schema = createForgotPasswordSchema(t);
    const result = schema.safeParse({ email });

    if (!result.success) {
      const errors = mapFieldErrors(result.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseEnterEmailAddress', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const { email: validatedEmail } = result.data;
    setFormErrors({});

    setLoading(true);

    try {
      // Request password reset OTP from API
      const data = await authService.requestPasswordResetOTP(validatedEmail);

      if (data && data.code === '00') {
        const userId = data?.data?.userId || data?.data?.user_id;
        if (!userId) {
          throw new Error(t('failedToSendOTP', { ns: 'auth' }));
        }
        logger.debug('OTP requested successfully', { email: validatedEmail });

        // Navigate to the new OTP verification page
        navigate('/reset-password-otp', {
          state: {
            email: validatedEmail,
            flow: 'password-reset'
          }
        });

        // Success - show success message
        setEmailSent(true);
        success(t('otpSentToEmailCheckInbox', { ns: 'auth' }));
        setEmail(validatedEmail);
      } else {
        throw new Error(data?.message || t('failedToSendOTP', { ns: 'auth' }));
      }
    } catch (err) {
      // Handle network or other errors
      logger.error('Password reset OTP request error', { error: err });
      setError(err.message || t('failedToSendOTP', { ns: 'auth' }));
      showError(err.message || t('failedToSendOTP', { ns: 'auth' }));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit} style={{
        paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '48px'
      }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1,
            maxWidth: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
            marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
            marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '32px'
          }}
        />

        <h2>{t('forgotPasswordTitle', { ns: 'auth' })}</h2>
        <p style={{ textAlign: 'center', marginBottom: '20px' }}>
          {emailSent
            ? t('redirectingToReset', { ns: 'auth' })
            : t('enterEmailForReset', { ns: 'auth' })
          }
        </p>

        {error && !emailSent && (
          <p className="error" role="alert" aria-live="assertive">{error}</p>
        )}
        {formErrors.email && !emailSent && (
          <p
            id={`${emailId}-error`}
            role="alert"
            aria-live="assertive"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-8px', marginBottom: '12px' }}
          >
            {formErrors.email}
          </p>
        )}
        {emailSent && (
          <p style={{ color: '#23bd00', textAlign: 'center', marginBottom: '10px' }}>
            ✓ {t('redirectingToReset', { ns: 'auth' })}
          </p>
        )}

        {!emailSent && (
          <div className="input-wrapper">
            <label htmlFor={emailId} className="sr-only">
              {t('emailAddress', { ns: 'auth' })}
            </label>
            <span className="input-icon"><i className="fa-solid fa-envelope"></i></span>
            <input
              type="email"
              id={emailId}
              placeholder={t('enterEmail', { ns: 'auth' })}
              value={email}
              onChange={(e) => {
                setEmail(e.target.value);
                if (formErrors.email) {
                  setFormErrors((prev) => {
                    const next = { ...prev };
                    delete next.email;
                    return next;
                  });
                }
                if (error) {
                  setError('');
                }
              }}
              disabled={loading}
              required
              autoFocus
              aria-invalid={!!formErrors.email}
              aria-describedby={formErrors.email ? `${emailId}-error` : undefined}
              autoComplete="email"
            />
          </div>
        )}

        {!emailSent && (
          <button type="submit" disabled={loading} style={{ width: '100%', marginBottom: '10px', backgroundColor: '#004895' }}>
            {loading ? t('redirecting', { ns: 'auth' }) : t('sendResetLink', { ns: 'auth' })}
          </button>
        )}

        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{ width: '100%', backgroundColor: '#23bd00' }}
        >
          {t('backToLogin', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
};

export default ForgotPassword;
